import{_ as o,o as p,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung075.jpg",q=JSON.parse('{"title":"Übung Lektion 47","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung47.md","filePath":"lektionen/uebung47.md"}'),i={name:"lektionen/uebung47.md"};function u(c,e,r,b,s,k){return p(),t("div",null,[...e[0]||(e[0]=[l('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-47" tabindex="-1">Übung Lektion 47 <a class="header-anchor" href="#ubung-lektion-47" aria-label="Permalink to &quot;Übung Lektion 47&quot;">​</a></h1><p>A) Übersetzen Sie:</p><p>यदि गच्छसि गच्छ त्वम् । अहं न गमिष्यामि ॥१॥</p><blockquote><p>Wenn du gehen willst, dann geh! Ich werde nicht gehen.</p></blockquote><p>आर्य प्रेक्षस्व मे परिभवम् ॥२॥</p><blockquote><p>Edler, sieh meine Demütigung!</p></blockquote><p>भो राम यदि मया गन्तव्यं तदैषा कन्यापि मम सहायिनी भवतु ॥३॥</p><blockquote><p>Herr Rāma, wenn ich gehen muss, dann soll auch dieses Mädchen meine Begleiterin sein.</p></blockquote><p>आर्ये तिष्ठ तिष्ठ । न त्वया भेतव्यम् ॥४॥</p><blockquote><p>Gnädige Frau, bleiben Sie stehen, bleiben Sie stehen. Sie brauchen keine Angst zu haben.</p></blockquote><p>प्रसीदत्वार्यः ॥५॥</p><blockquote><p>Beruhigen Sie sich, edler Herr!</p></blockquote><p>आर्ये स्वागतं ते ॥६॥</p><blockquote><p>Willkommen, gnädige Frau.</p></blockquote><p>आज्ञापयत्वार्यः किं मया क्रियतामिति ॥७॥</p><blockquote><p>Edler Herr, bitte befehlen Sie, was ich tun soll.</p></blockquote><p>युद्धाय युज्यस्व नैवं पापमवाप्स्यसि ॥८॥</p><blockquote><p>Rüste dich zum Kampf und dir wird so kein Übel geschehen.</p></blockquote><p>प्रश्नः : कस्मात्त्वं भीतः । प्रतिवचनम् : तस्य रामस्य गुणेभ्यः । प्रष्टा : के तस्य गुणा यस्य गृहं प्रविश्याशितव्यमपि नास्ति ॥९॥</p><blockquote><p>Frage: Wovor fürchtest Du dich? Antwort: vor den Vorzügen dieses Rāma. Frager: Was hat der für Vorzüge, in dessen Haus nichts Essbares ist, wenn man kommt.</p></blockquote><p>तवैव हस्ते शस्त्रं तिष्ठतु ॥१०॥</p><blockquote><p>Das Schwert in Deiner Hand bleibe stehen!</p></blockquote><p>भवति न ते परिभवस्तत्रभवतो रामस्य निवेदयितव्यः ॥११॥</p><blockquote><p>Gnädige Frau, ihre Demütigung soll Herrn Rāma nicht berichtet werden.</p></blockquote><p>B.) Übersetzen Sie ins Sanskrit (verwenden Sie den Imperativ):</p><p>1. Ich will erhalten werden.</p><blockquote><p>भ्रियै ॥१॥</p></blockquote><p>2. Er soll zufrieden sein.</p><blockquote><p>तुष्यतु ॥२॥</p></blockquote><p>3. Wir wollen rufen.</p><blockquote><p>ह्वयाम ॥३॥</p></blockquote><p>4. Ich will mich dir (चतुर्थ्या) beugen.</p><blockquote><p>तुभ्यं नमानि । नमानि ते ॥४॥</p></blockquote><p>5. Diese Tat soll getan werden.</p><blockquote><p>एतत्कर्म क्रियताम् ॥५॥</p></blockquote><p>6. Sie sollen schlafen (Passivkonstruktion).</p><blockquote><p>भवता सुप्यताम् ॥६॥</p></blockquote><p>7. Mein Sohn strebe nach Reichtum!</p><blockquote><p>पुत्र धने / धनं / धनाय यतस्व ॥७॥</p></blockquote><p>8. Beginnt das Studium!</p><blockquote><p>अध्ययनमारभध्वम् ॥८॥</p></blockquote><p>9. Gebt (प्र-यम्) den Ahnvätern Reisbällchen!</p><blockquote><p>पितृभ्यः पिन्दान्प्रयच्छत ॥९॥</p></blockquote><p>10. Sie sollen sich freuen!</p><blockquote><p>नन्दन्तु ॥१०॥</p></blockquote><p>11. Ich will auf die Welt hinabblicken.</p><blockquote><p>लोकमवेक्षै ॥११॥</p></blockquote><p>12. Wir wollen nach Benares gehen (पद्).</p><blockquote><p>काशीं पद्यआमहै ॥१२॥</p></blockquote><p>13. Sie (pl.) sollen als Opferherren die Götter mit einem Opfer verehren.</p><blockquote><p>देवान्यजन्ताम् ॥१३॥</p></blockquote><p>14. Singe ein Loblied!</p><blockquote><p>स्तोत्रं गाय ॥१४॥</p></blockquote><p>15. Söhne sollen mir geboren werden!</p><blockquote><p>पुत्रा मह्यं / मे जायन्ताम् ॥१५॥</p></blockquote><p>16. Ich will dir mein Haus zeigen.</p><blockquote><p>तुभ्यं मम / मे गृहं दिशानि । त्वां ... दर्शयानि ॥१६॥</p></blockquote><p>17. Gehe von mir weg!</p><blockquote><p>मत्प्रव्रज । मद्व्रज ॥१७॥</p></blockquote><p>18. Er soll befreit werden!</p><blockquote><p>मुच्यताम् ॥१८॥</p></blockquote><p>19. Ich will deine Gattin behüten.</p><blockquote><p>तव भार्यां रक्षाणि ॥१९॥</p></blockquote><p>20. Stirb, Feind!</p><blockquote><p>शत्रो म्रियस्व ॥२०॥</p></blockquote><p>21. Kämpft!</p><blockquote><p>युध्यध्वम् ॥२१॥</p></blockquote><p>22. Sie (pl.) mögen befehlen.</p><blockquote><p>आज्ञापयन्तु ॥२२॥</p></blockquote><p>23. Wir wollen in deinem Haus wohnen.</p><blockquote><p>तव गृहे वसाम ॥२३॥</p></blockquote><p>24. So soll es geschehen!</p><blockquote><p>एवं भवतु । एवं वर्तताम् ॥२४॥</p></blockquote><p>25. Schlage das Pferd!</p><blockquote><p>अश्वं तुद ॥२५॥</p></blockquote><p>26. Sie (pl.) sollen umherirren.</p><blockquote><p>भ्रमन्तु । भ्राम्यन्तु ॥२६॥</p></blockquote><p>27. Berauscht euch!</p><blockquote><p>माद्यत ॥२७॥</p></blockquote><p>28. Das Pferd soll die Last ziehen.</p><blockquote><p>अश्वो भारं कर्षतु ॥२८॥</p></blockquote><p>29. Wir wollen die Welten in Ordnung bringen.</p><blockquote><p>लोकान्कल्पयाम ॥२९॥</p></blockquote><p>30. Trinke den Trank!</p><blockquote><p>पानं पिब ॥३०॥</p></blockquote><p>31. Denke!</p><blockquote><p>मन्यस्व ॥३१॥</p></blockquote><p>32. Sie (pl.) sollen besiegt werden!</p><blockquote><p>जीयन्ताम् ॥३२॥</p></blockquote><p>33. Wir wollen von dir geführt werden.</p><blockquote><p>त्वया नीयामहै ॥३३॥</p></blockquote><p>34. Es möge zum Glück gereichen (geschehen)! (Segenswunsch)</p><blockquote><p>सुखाय भवतात् ॥३४॥</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: माद्यत<br> Toddy-Shop = കള്ള്<br> Kochi = കൊച്ചി<br> [Bildquelle: Nice Logo. -- <a href="http://www.flickr.com/photos/nicelogo/869115128/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/nicelogo/869115128/</a>. -- Zugriff am 2009-01-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',95)])])}const h=o(i,[["render",u]]);export{q as __pageData,h as default};
